const body = $input.first().json.body || $input.first().json;

const admin_token = body.admin_token || null;
const user_id     = body.user_id     || null;
const action      = (body.action || '').toLowerCase().trim();
const feature_key = (body.feature_key || '').toLowerCase().trim();
const reason      = body.reason      || 'No reason provided';

// Fail fast on missing fields
if (!admin_token)  throw new Error('Missing required field: admin_token');
if (!user_id)      throw new Error('Missing required field: user_id');
if (!action)       throw new Error('Missing required field: action');
if (!feature_key)  throw new Error('Missing required field: feature_key');

// Validate action values
const validActions = ['grant', 'revoke'];
if (!validActions.includes(action)) {
  throw new Error(`Invalid action '${action}' — must be 'grant' or 'revoke'`);
}

// Whitelist of all valid feature keys — prevents arbitrary column injection
const validFeatureKeys = [
  'launchpad_tool_1',
  'launchpad_tool_2',
  'launchpad_tool_3',
  'launchpad_tool_4',
  'launchpad_tool_5',
  'launchpad_tool_6',
  'launchpad_tool_7',
  'launchpad_tool_8',
  'launchpad_tool_9',
  'launchpad_tool_10',
  'nova_os_lead_capture',
  'nova_os_followup',
  'nova_os_booking',
  'nova_os_nurture',
  'nova_os_reporting',
  'nova_os_sales',
  'ai_operator_access',
  'subagent_access',
  'credits_gated'
];

if (!validFeatureKeys.includes(feature_key)) {
  throw new Error(`Invalid feature_key '${feature_key}' — not a recognised entitlement column`);
}

// Simple deterministic hash of the admin token for audit log (never store raw token)
const crypto = require('crypto');
const token_hash = crypto.createHash('sha256').update(admin_token).digest('hex').substring(0, 16);

return [{
  json: {
    admin_token,
    token_hash,
    user_id,
    action,
    feature_key,
    reason,
    feature_value: action === 'grant',
    now: new Date().toISOString()
  }
}];

const fetchResult = $input.first().json;
const origin = $('Parse, Validate & Hash Token').first().json;

const record = Array.isArray(fetchResult) ? fetchResult[0] : fetchResult;

if (!record || !record.user_id) {
  throw new Error(`No user_entitlements record found for user_id: ${origin.user_id}. Cannot apply override.`);
}

const current_value = record[origin.feature_key];
const no_change = current_value === origin.feature_value;

return [{
  json: {
    ...origin,
    entitlement_exists: true,
    current_value,
    no_change,
    pre_state: record
  }
}];

// Build a dynamic PATCH body with only the target feature key
const origin = $input.first().json;

const patch_body = {};
patch_body[origin.feature_key] = origin.feature_value;
patch_body['updated_at'] = origin.now;

return [{
  json: {
    ...origin,
    patch_body: JSON.stringify(patch_body)
  }
}];

const patchResult = $input.first().json;
const origin = $('Build Dynamic PATCH Body').first().json;

const record = Array.isArray(patchResult) ? patchResult[0] : patchResult;

if (!record || !record.user_id) {
  throw new Error(`PATCH to user_entitlements returned no data for user_id: ${origin.user_id}. Check Supabase RLS.`);
}

const new_value = record[origin.feature_key];
const applied   = new_value === origin.feature_value;

return [{
  json: {
    ...origin,
    patch_confirmed: applied,
    new_value,
    updated_entitlements: record
  }
}];
